INSERT INTO knowledge_documents (id, source_path, title, kind, tags, content, summary, chunk_count, is_archive, metadata, created_at, updated_at) VALUES
(gen_random_uuid(), 'kb/international/221', '跨区域运营资源配置', 'spec', '{国际化,运营,资源}', '跨区域运营资源分配三原则：1）优先配给高ROI市场——按IRR排序分配资金、人才、设备资源，各季度更新排名；2）人才共享池——区域总监级跨市场调配，核心岗位（店长/市场/运营）全球人才库持续更新；3）设备调拨机制——同区域市场间设备冗余调拨（如泰国淡季设备调越南旺季），降低闲置率15-20%。总部与区域权责划分：总部负责品牌/系统/IP/战略/资金，区域负责运营/市场/采购/本地关系。组织架构：总部国际事业部→区域总经理（每区1人，管理3-5个市场）→国家经理（每国1人）→门店店长。考核：区域营收达成率/利润达成率/门店数量增长率/本地团队满意度。会议频率：总部-区域周会40min/区域-国家周会30min/国家-门店日晨会15min。', '跨区域运营的三原则+权责划分+组织架构+考核体系', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/222', '海外门店绩效管理体系', 'spec', '{国际化,绩效,考核}', '海外门店绩效管理五步法：1）目标设定——年度目标自上而下（总部→区域→门店→个人），门店核心KPI（营收完成率+利润率+会员增长+客户满意度+员工满意度），权重分别为30/25/15/15/15。2）过程跟踪——月度绩效面谈（店长+国家经理），周报核心数据自动推送，异常即时干预。3）评估——季度评估（绩效+能力双维度），年度全面评估。4）反馈——评估结果与薪酬/晋升/培训挂钩，店长等级（S/A/B/C）对应奖金系数（150%/100%/80%/50%）。5）改进——C级店长PIP计划（3个月改进期），仍不合格调整或换人。本地化考绩：增加本地市场特定指标（如中东女性满意度/东南亚家庭套餐转化率），权重不超过20%。', '海外门店绩效五步管理法+店长评级/奖金挂钩方案', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/223', '海外市场税务与财务筹划', 'spec', '{国际化,税务,财务}', '海外税务筹划五大要点：1）转让定价——关联交易需符合独立交易原则，准备转让定价文档（三层文档标准），避免被税务调整+罚款；2）常设机构风险——短期项目怕被认定为PE（需缴企业所得税），控制派驻时间<183天/年；3）DTT利用——中国与多国签有避免双重征税协定，股息预提税可从30%降至5-10%；4）盈亏抵补——新店前3年亏损可向后结转（各国5-20年不等），尽量先亏后盈；5）退税——出口设备增值税退税（13%），注意退税申报时限（90天）。财务报告要求：各市场按月出本地GAAP报表+总部合并报表调整（中国GAAP/IFRS差异），季度审计由四大会所之一执行。税务筹划核心原则：合法合规，避免激进避税方案。', '五维海外税务筹划+财务报告要求+合规底线', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/224', '海外市场物流与仓储体系', 'spec', '{国际化,物流,仓储}', '海外物流仓储体系规划：1）区域仓——东南亚（泰国曼谷，覆盖7国，面积2000㎡，月租金2万美元，65天周转）；中东（迪拜Jafza，覆盖GCC+北非，1500㎡，月租3万美元）；2）配送模式——区域仓集中配送（每周固定线路），门店紧急订单（本地供应商24h达），跨境直邮（电商SKU）。3）清关——准备完整报关单证（发票/箱单/原产地证/HS Code分类），聘请当地清关行，预定关税（货值5-30%）。4）逆向物流——维修品返厂（退回区域仓维修后回门店），滞销品调拨（同区域调拨减少损失），报废品处理（当地环保合规）。5）WMS系统——多语种入库/出库/库存/调拨功能，与总部系统实时同步（库存数据15min延迟内）。KPI：配送准时率≥95%/库存准确率≥99%/破损率≤0.5%/订单处理≤4h。', '区域仓规划+配送/清关/逆向物流/WMS全方案', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/225', '海外门店数字化建设', 'spec', '{国际化,数字化,系统}', '海外门店数字化建设七模块：1）收银系统——对接当地支付网关，支持多币种实时换算，离线模式可72小时运行；2）会员系统——国际版神机营P-36，多语言支持，本地化权益配置；3）设备管理系统——多国设备台账（含认证信息/维保记录），远程诊断管理；4）运营数据平台——时区/币种/语言自适应，日结自动同步，断网本地缓存；5）员工管理——多语种排班，本地劳工法合规（工时/休假/社保），考勤跨市场对比；6）营销系统——各渠道适配（TikTok API/Line OA/Instagram API），多时区自动定时；7）监控系统——本地存储+云端备份，总部实时查看，AI异常自动告警（客流/设备/安全）。部署策略：优先部署收银+会员+设备+数据四核心模块（前3月），后三模块（6-12月滚动），优先使用云端SaaS部署，内网数据走专线加密。', '海外门店数字化七模块+分阶段部署策略', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/226', '国际市场人才梯队建设', 'spec', '{国际化,人才,梯队}', '国际市场人才梯队三层结构：1）总部国际班（8-12人）——国际事业部负责人+区域总监+职能专家（HR/MKT/FIN/IT/法务/PR），全员英语C1+第二外语优先，需有3年以上跨文化管理经验；2）区域管理层（15-25人）——国家经理+区域运营/市场/HR/财务，本地华人或外籍华裔优先，英语B2+，需在总部培训3个月；3）门店管理层（50-80人/年）——当地店长+副店长+组长，本地人为主，需通过总部认证培训和考核。人才来源：内部外派（占20%，核心岗）+本地招聘（60%，执行层）+海外招聘（20%，华裔/留学生）。培训投入：年薪总额的3-5%。关键岗位保留：店长竞业+期权+住房补贴+子女教育补贴。每季度人才盘点一次（9宫格），核心岗位保持2:1继任率。', '三层国际人才梯队+来源配比+培训保留方案', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/227', '海外品牌IP授权与合作', 'spec', '{国际化,IP,合作}', '海外品牌IP合作三种模式：1）购买国际IP授权——Disney/漫威/宝可梦等全球IP，授权费¥100-500万/年+分成，适合旗舰店引流；2）中国IP出海——国潮IP（故宫/敦煌/哪吒/原神/王者荣耀）授权海外，授权费相对低（¥20-100万/年），有文化输出价值；3）联合开发IP——与本地设计师/工作室联合开发，共享版权，适合长期经营。IP合作执行：选IP->谈判（3-6月）->设计联名产品（2-3月）->生产（45天）->门店推广（提前14天预热）->上市（1-3月限时）->数据复盘。IP联名效果：平均营收提升20-50%，新客提升30-80%，社媒曝光提升200-500%。东南亚对日漫IP接受度最高，中东偏西方IP，日韩接受国潮IP逐年上升。预算：年IP费用占营收5-8%，不超过10%。', '三种海外IP合作模式+执行流程+各市场偏好', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/228', '海外市场本地化营销日历', 'spec', '{国际化,营销,日历}', '海外市场本地化营销日历编制：东南亚（主要国家）——1月元旦+春节（红包主题）/2月情人节（情侣挑战赛）/4月宋干节（泼水主题+水枪大赛）/6月学校假期（亲子月）/7-8月暑假（学生套餐）/10月万圣节+年终派对/12月圣诞+跨年。中东——3月开斋节（家庭活动+夜间优惠）/6月宰牲节/11月阿联酋国庆/Dubai Shopping Festival（1-2月）/Ramadan期间夜间营业+开斋活动。日韩——1月新年/2月情人节/3月白色情人节/4月樱花季（限定主题）/5月黄金周/7-8月暑假+花火大会/10月万圣节/12月圣诞。每月至少1个本地化主题+1个全球统一活动日+1个临时热点响应。营销日历提前一季度编制+每月微调。预算按主题分配：主题大（40%）/中（35%）/小（25%）。', '东南亚/中东/日韩三大区域年度营销日历编制', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/229', '海外门店客诉与品质监控', 'spec', '{国际化,服务,品质}', '海外客诉处理升级版：渠道——门店当面/电话/WhatsApp（东南亚+中东主力）/LINE（日韩）/Facebook Messenger/Google Maps评价/App Store评论。处理时效：回复≤15min（WhatsApp）/4h（邮件）/24h（评价平台）。语言：当地语言+英文双语，复杂客诉转接区域客服中心（曼谷/迪拜）。升级机制：L1导玩员（5min安抚+小补偿≤等值$20）→L2店长（4h处理+补偿$20-50）→L3国家经理（24h+补偿$50-200+书面道歉+VIP补偿）→L4总部区域总监（48h+重大补偿+公关介入）。品质监控：季度神秘访客（NPS评估+服务评分）+月度客户满意度调查（净推荐值NPS目标≥+40）+周评价分析（差评关键词监控+趋势预警）。神机营系统支持多语言客诉工单+自动分配+回访追踪。', '多国客诉渠道+四级升级机制+品质监控体系', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/230', '国际市场入驻机构对接清单', 'spec', '{国际化,机构,合作}', '国际市场入驻需对接的机构清单：泰国——BOI投资促进委员会（税收优惠申请）、Tourism Authority（旅游促进）、Shopping Mall Association（商场合作）、E-Sport Federation（电竞合作）。印尼——BKPM投资协调委员会（外资审批）、APMI游戏协会（行业资源）。越南——Ministry of Culture（娱乐许可）、VINAGA游戏协会。中东——Dubai Economy（营业执照）、Dubai Tourism（旅游推广）、Saudi General Entertainment Authority（沙特娱乐局，GEA牌照必备）。对接时间：机构注册/许可（2-6个月），行业协会会员（1-3个月），政府关系维护（持续）。费用：政府规费每个市场$2,000-10,000/年，行业协会会员$500-2,000/年，政府关系维护$10,000-50,000/年（含活动/赞助/捐）。建议：优先加入本地商会（如新加坡中华总商会/泰国中华总商会），通过商会建立初始政府和合作方关系。', '东南亚+中东五大市场机构对接清单+费用估算', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/231', '国际化产品适配原则', 'spec', '{国际化,产品,适配}', '国际化产品适配五大原则：1）UI多语言——后端实现i18n，前端按浏览器语言自动切换，支持RTL（阿拉伯语/希伯来语）显示，长度预留30%以上；2）支付方式——必须支持当地主流支付（不做就是区域），建议最少3种（卡+电子钱包+现金），集成支付网关统一对接；3）货币与时区——显示当地货币+可切换显示美元，时区自动检测（服务器UTC+8+当地时区双存储）；4）本地法规——年龄验证（各地成年标准不同/日本20岁/印尼17岁/中东18-21），内容审查（中东禁止赌博元素暗示），数据合规；5）本地节日与习惯——营业时间调整（中东周五缩短/东南亚午休），促销节奏适配。核心原则：最小产品可全球化（MVP+本地化配置层），不做全定制产品。', '五大国际化产品适配原则+各市场差异化配置', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/232', '跨境物流成本优化方案', 'spec', '{国际化,物流,成本}', '跨境物流成本优化六方案：1）拼柜集中发——整合多家门店设备需求统一拼柜FCL，单柜成本$2,500-5,000（上海→曼谷），比LCL省30-40%；2）海运比空运——海运35天成本$1-3/kg，空运3天$5-10/kg，品类优化（急件空运/普件海运/备件寄售海运）；3）关税筹划——用好FTA（中国-东盟零关税/中国-阿联酋13%优惠税率），HS Code准确归类（避免重分类补税+罚款）；4）本地化采购——当地采购低成本耗材（如清洁用品/办公用品/T恤工服）减少海运量，本地采购占比目标30%+；5）逆向物流优化——维修品集中到区域维修中心（非回中国），报废品当地处理，返修率控制在3%以内；6）仓储成本——区域仓选址（保税仓可延迟付税/免税仓可转卖本地/普通仓最灵活），租期谈3+2年降租10-15%。年度物流成本控制目标：占营收≤3%（初期可达5-8%，逐步优化）。', '六项跨境物流优化方案+成本控制目标≤营收3%', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/233', '海外门店设计标准', 'spec', '{国际化,设计,标准}', '海外门店设计标准化指南：1）面积标准——旗舰店800-1200㎡/标准店400-600㎡/mini店200-300㎡/快闪店50-100㎡；2）分区标准——设备区60%/休息饮食区15%/活动区10%/收银区5%/通道10%；3）视觉元素——品牌色（可保留高识别度色，如金色+品牌蓝），Logo位置（入口+收银台+设备区循环），标准灯具（照度≥300lux，设备区500lux）；4）安全设计——双出口（门宽≥1.4m），灭火器间距≤30m，地板防滑系数≥0.5，所有材料阻燃B1级；5）本地化装饰——融入当地文化元素（东南亚热带植物/中东几何纹样/日韩极简），20%面积留作本地化装饰区；6）可持续设计——LED照明+自然采光/节水洁具/可回收装修材料，建议申请LEED认证（中东加分项）。设计图纸：总部提供80%标准设计，本地设计院完成20%本地化深化。', '海外门店面积/分区/视觉/安全/本地化/可持续六大设计标准', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/234', '海外团队激励与文化建设', 'spec', '{国际化,激励,文化}', '海外团队跨文化激励方案三大原则：1）尊重本地文化——东南亚集体主义（班组竞赛/团队奖金/月度最佳团队），中东权威层级（顶级绩效面谈+公开表彰），日韩等级（年功序列+奖状等级分明），欧美个人主义（个人KP I+即时奖金+灵活工作）。2）统一文化内核——品牌使命（Bring Joy Worldwide）多语言版本，价值观（好玩/成长/诚信/共赢）本地化翻译+案例本地化，口号全球统一+当地谐音化传播。3）激励体系——短期（月度个人奖$100-500+门店奖$500-2,000）+中期（季度达成奖1-2月工资+优秀员工总部培训参观1周）+长期（年度全球年会+期权+海外管培晋升）。文化融合举措：各国员工互访（季度1次，区域间），全球价值观日（每季度，线上线下），总部文化手册多语版分发。', '三大原则跨文化激励方案+短中长期激励体系+文化融合活动', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/235', '海外市场用户增长策略', 'spec', '{国际化,增长,用户}', '海外市场用户增长五策略：1）数字营销——Google Ads（搜索+Display+YouTube in-stream）目标CPA $3-8/install，Meta Ads（Facebook+Instagram）精准定向兴趣人群，TikTok Ads（In-feed+Spark Ads）本地KOL+挑战赛；2）本地化内容——当地语言SEO（Google My Business优化+本地目录提交），当地平台运营（Line OA泰国/WhatsApp Blast中东/WeChat东南亚华人）；3）社区裂变——推荐奖励（推荐新客双方得币/积分），家庭套餐（买三送一，一人办全家玩），企业团购（公司出游/Team Building渠道）；4）跨界合作——与当地热门品牌联名（奶茶/餐饮/电影院）+与社区KOL合作（社区I影响者=信任度高）+与旅游平台合作（携程/Klook国际版推送）；5）留存复购——首次到店策略（首充翻倍+7天有效，促再访），会员自动充值（储值卡自动续，月末双重积分），流失率≤5%/月目标。各渠道获客成本：数字营销$3-8/社区裂变$1-3/跨界合作$2-5/KOL$5-15。', '五策略海外用户增长+各渠道获客成本对比', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/236', '海外加盟商管理体系', 'spec', '{国际化,加盟,管理}', '海外加盟商管理六大模块：1）加盟商筛选——资金实力≥$300K+行业经验/当地资源+品牌认同+开店经历（优先有mall资源者），面试2轮+背调+实地考察。2）加盟合同——加盟期5年+续约条款、加盟费$20-50K一次性、年管理费5-8%（保底$15K/年）、设备采购总部指定价、系统月费$500-1,000、市场基金3%。3）培训与开业——总部培训4周（线下中英文+考核）+驻场辅导2周支持+首家店6个月督导期+后续年2次巡查。4）持续支持——运营SOP手册年度更新、新品/促销统一方案+本地调整建议、季度云会议+年度加盟商大会。5）监督审计——神秘访客（季度）+运营数据月报+财务审计年检+KPI不达标PIP（3个月）。6）退出机制——合同终止后品牌元素清理/存货回购/竞业禁止2年/总部优先回购权。目标：首年开店5-10家，续约率≥80%，加盟商盈利率≥85%。', '六大海外加盟管理模块+首年目标5-10家/续约率80%+', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/237', '国际市场公共关系与品牌建设', 'spec', '{国际化,PR,品牌}', '国际市场PR+品牌建设五维度：1）媒体关系——建立本地媒体列表（主流/商业/娱乐/科技类各5-10家），季度媒体见面会+新品体验会+PR KIT（品牌故事+数据解读+CEO专访资源）。2）行业活动——参加国际游艺博览会（IAAPA展/亚洲景点展/迪拜娱乐展）+举办本地行业论坛+赞助行业协会活动。3）声誉管理——本地媒体监测（新闻+博客+论坛），制定发言人制度（仅限CEO+区域总经理对外发言），媒体培训（危机18条金句+不回负面说NO）。4）CSR——每月1次社区活动（弱势儿童关怀/网吧青少年/环保）+公益合作（与当地学校合作实习生项目）+年度CSR报告。5）品牌活动——旗舰店开幕（政府+媒体+KOL邀请，预算$10-30K）+年度品牌盛典（用户活动+行业峰会+媒体发布会，预算$50-100K）。KPI：媒体曝光量/年增长≥50%/PR价值（AVE）≥广告投入的3倍/CSR参与量/年≥1,000人次。', '五维国际PR体系+媒体/活动/CSR/品牌KPI', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/238', '海外市场数据隐私与合规', 'spec', '{国际化,数据,隐私}', '海外市场数据隐私要求分区域：欧洲——GDPR（通用数据保护条例）严格，罚款全球营收4%或€2,000万取高，需DPA协议+DPO任命（可外部）+数据保留≤3年+用户权利（访问/删除/可携带）+数据泄露72h内通知；东南亚——多数参照GDPR（新加坡PDPA/泰国PDPA/印尼PDP），要求类似但罚则稍轻（新加坡最高S$1百万）；中东——阿联酋PDL（联邦法）和DIFC/ADGM特定条例，迪拜自由区有独立DP law；日韩——日本APPI+韩国PIPA，数据本地化要求+跨域传输审批。合规操作：1）数据映射——梳理采集/存储/处理/传输的PII分布；2）隐私政策——多语言+易懂+需主动同意（cookie+营销同意分离）；3）安全措施——加密存储（AES-256）/传输加密（TLS 1.3）/访问控制RBAC/日志审计；4）跨境传输——数据跨境需合法机制（SCCs标准合同条款/Binding Corporate Rules/充分性认定）。', '各区域数据隐私法规+GDPR/PDPA/PIPA要求+合规操作指南', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/239', '海外门店能耗与环境管理', 'spec', '{国际化,能耗,环境}', '海外门店能耗管理四项措施：1）空调——Smart AC温度控制（26°C恒温）+分区控制（设备区26°C/休息区25°C/办公区27°C）+夜间节能模式，空调占门店能耗45-55%，可优化30%；2）照明——全部LED替换（比传统省电70%），走廊/卫生间PIR感应灯，营业结束自动关闭展示灯，照明占能耗25-30%；3）设备——带能源之星评级设备优先/待机功耗≤5W/不使用时自动休眠，设备占能耗15-20%；4）可再生能源——屋顶太阳能板（热带地区回本周期3-5年），绿电采购合同（欧美市场可选），节能效果可降低总能耗20-30%。环境管理：废水排放合规（清洁废水需隔油池），垃圾分类（一般/可回收/危险品），噪音控制（白天≤55dB/夜晚≤45dB，营业区隔音处理）。ESG报告要求：部分市场（欧洲/日本）需提供年ESG报告，包含碳排放数据+水电消耗+员工福利。', '四维能耗管理+环境合规+ESG报告要求', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/240', '跨文化法律纠纷处理', 'spec', '{国际化,法律,纠纷}', '跨文化法律纠纷三大类型和应对：1）合同纠纷——供应商违约/项目延误/加盟商欠费/合作伙伴纠纷。优先仲裁（成本低于诉讼、保密性、可执行性强），推荐仲裁地（SIAC新加坡/HKIAC香港/ICC巴黎），合同明确约定仲裁条款+适用法律+语言。2）劳动纠纷——外籍员工解雇/本地员工争议/社保欠缴。当地劳动法通常偏向员工（尤其是东南亚），解雇必须符合法定程序（书面警告x2+面谈+经济补偿），争议可走调解（省时省费用）→劳动法庭（3-6个月）。3）知识产权——商标被抢注（海外常见！建议开店前6-12个月注册）+设备抄袭（专利保护+公证取证）+品牌模仿。应对：全球主要市场商标注册（TMCH服务)+Google/Shopee下架+当地律所发函+海关备案（拦截仿品出口）。法律费用预算：年$30-80K（含常法律所+专项+知识产权注册维护），新市场首年$50-100K。', '三大跨文化法律纠纷类型+仲裁地选择+费用预算', 3, false, '{}'::jsonb, NOW(), NOW());
